def make_shap_plot(ranked_features: list[tuple[str, float]]) -> plt.Figure:
    top_ranked = ranked_features[:8]
    series = pd.Series(
        [value for _, value in top_ranked],
        index=[format_feature_name(feature) for feature, _ in top_ranked],
    ).sort_values()

    fig, ax = plt.subplots(figsize=(8.2, 4.8))
    colors = ["#ff6b81" if value > 0 else "#67f7ae" for value in series.values]
    ax.barh([format_feature_name(name) for name in series.index], series.values, color=colors)
    ax.axvline(0, color="#8fa3ca", linewidth=1)
    ax.set_facecolor("#0c1628")
    fig.patch.set_facecolor("#0c1628")
    ax.set_title("Feature Contribution Map", color="#edf4ff", fontsize=15, pad=12)
    ax.set_xlabel("SHAP Contribution", color="#b6c8e6")
    ax.tick_params(axis="x", colors="#90a3c8")
    ax.tick_params(axis="y", colors="#edf4ff")
    ax.grid(axis="x", linestyle="--", alpha=0.16, color="#8fa3ca")
    for spine in ax.spines.values():
        spine.set_visible(False)
    plt.tight_layout()
    return fig


def build_trend_data(history: list[dict[str, object]]) -> pd.DataFrame:
    phishing_count = sum(1 for item in history if item["status"] == "phishing")
    safe_count = len(history) - phishing_count
    base = max(phishing_count, 2)
    points = []
    for index in range(7):
        points.append(
            {
                "day": (datetime.utcnow() - timedelta(days=6 - index)).strftime("%a"),
                "phishing": max(1, base + (index % 3) - 1),
                "safe": max(1, safe_count + (2 - (index % 3))),
            }
        )
    return pd.DataFrame(points)


