        {
            "category": ["Blocked Threats", "Safe URLs", "Suspicious Domains"],
            "count": [phishing * 3 + 4, safe * 2 + 3, phishing + 2],
        }
    )


def add_history_entry(url: str, status: str, probability: float, risk_score: int) -> None:
    entry = {
        "timestamp": datetime.utcnow().strftime("%H:%M"),
        "url": get_hostname(url),
        "status": status,
        "probability": probability,
        "risk_score": risk_score,
    }
    st.session_state.scan_history = [entry] + st.session_state.scan_history[:7]


