import { useState } from "react";

function percent(value) {
  return `${(value * 100).toFixed(2)}%`;
}

function App() {
  const [url, setUrl] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [result, setResult] = useState(null);

  async function handleScan() {
    if (!url.trim()) {
      setError("Enter a URL before scanning.");
      return;
    }

    setLoading(true);
    setError("");
    setResult(null);

    try {
      const response = await fetch(`/api/scan`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ url: url.trim() })
      });

      if (!response.ok) {
        const payload = await response.json().catch(() => ({}));
        throw new Error(payload.detail || "Scan failed");
      }

      const payload = await response.json();
      setResult(payload);
    } catch (err) {
      setError(err.message || "Unable to connect to backend API.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="page">
      <main className="container">
        <section className="hero">
          <p className="eyebrow">PhishGuard AI</p>
          <h1>Simple URL safety check</h1>
          <p className="subtitle">
            Paste a link, run one scan, and get a clear phishing risk summary.
          </p>
        </section>

        <section className="panel">
          <div className="input-group">
            <input
              value={url}
              onChange={(e) => setUrl(e.target.value)}
              placeholder="https://example.com"
            />
            <button onClick={handleScan} disabled={loading}>
              {loading ? "Scanning..." : "Scan URL"}
            </button>
          </div>

          {error && <p className="error">{error}</p>}

          {!result && !error && (
            <p className="hint">Try a URL like `https://example.com/login`.</p>
          )}

          {result && (
            <section className="result">
              <div className="summary">
                <div className="stat">
                  <span className="label">Status</span>
                  <strong className={`status ${result.prediction}`}>
                    {result.prediction.toUpperCase()}
                  </strong>
                </div>
                <div className="stat">
                  <span className="label">Confidence</span>
                  <strong>{percent(result.confidence)}</strong>
                </div>
                <div className="stat">
                  <span className="label">Risk score</span>
                  <strong>{result.risk_score}%</strong>
                </div>
              </div>

              {result.decision_reason && (
                <div className="callout">
                  <span className="label">Why this result</span>
                  <p>{result.decision_reason}</p>
                </div>
              )}

              <div className="details">
                <h2>Top signals</h2>
                <ul>
                  {result.explanation.map((item) => (
                    <li key={item.feature}>
                      <span>{item.feature.replaceAll("_", " ")}</span>
                      <strong>{item.contribution.toFixed(4)}</strong>
                    </li>
                  ))}
                </ul>
              </div>

              <div className="details">
                <h2>Feature chart</h2>
                <img
                  src={`data:image/png;base64,${result.shap_plot_base64}`}
                  alt="SHAP chart"
                />
              </div>
            </section>
          )}
        </section>
      </main>
    </div>
  );
}

export default App;

