    score += int(features.get("has_https_token_in_host_or_path", 0)) * 2
    score += int(features.get("is_suspicious_tld", 0)) * 2
    score += min(int(features.get("num_suspicious_keywords_host", 0)), 2) * 2
    score += min(int(features.get("num_suspicious_keywords_path", 0)), 2)
    score += int(features.get("path_length", 0) >= 24)
    score += int(features.get("num_slashes", 0) >= 5)
    score += int(features.get("has_percent_encoding", 0))
    score += int(features.get("has_port", 0))
    score += int(features.get("num_subdomains", 0) >= 3)
    score += int(not features.get("uses_https", 0))
    return score


def decide_prediction(
    url: str,
    probability: float,
    threshold: float,
    features: dict[str, Any],
) -> tuple[str, float, float, int, str | None]:
    score = suspicious_signal_score(features)
    has_no_red_flags = (
        score == 0
        and int(features.get("uses_https", 0)) == 1
        and int(features.get("num_suspicious_keywords", 0)) == 0
        and int(features.get("has_ip_address", 0)) == 0
        and int(features.get("has_shortener", 0)) == 0
        and int(features.get("is_suspicious_tld", 0)) == 0
    )

    if is_trusted_domain(url):
        return "safe", min(probability, 0.05), max(1.0 - probability, 0.95), min(int(round(probability * 100)), 5), (
            "Trusted domain safeguard applied"
        )

    if has_no_red_flags:
        return "safe", min(probability, 0.1), max(1.0 - probability, 0.9), min(int(round(probability * 100)), 10), (
            "No strong phishing signals detected in the URL"
        )

    if score >= 4 and probability >= 0.25:
        return "phishing", max(probability, 0.9), max(probability, 0.9), max(int(round(probability * 100)), 90), (
            "Multiple URL-level phishing signals detected"
        )

    if probability >= max(threshold, 0.9) and score >= 1:
        return "phishing", probability, probability, int(round(probability * 100)), (
            "High model confidence supported by suspicious URL structure"
        )

    if probability >= threshold and score >= 2:
        return "phishing", probability, probability, int(round(probability * 100)), None

    return "safe", min(probability, 0.35), max(1.0 - probability, 0.7), min(int(round(probability * 100)), 35), (
        "Model score was overridden because URL-level phishing signals were weak"
    )

